// ─────────────────────────────────────────────
// Parse incoming WhatsApp message + filter + media detection
// ─────────────────────────────────────────────
const body = $input.item.json.body || $input.item.json;
const msg = body.message || body;

const chatId = msg.chatid || msg.chat?.id || msg.from || body.chat?.wa_chatid || '';
const messageId = msg.messageid || msg.id || '';
const senderName = msg.senderName || msg.sender?.name || msg.pushname || msg.notifyName || 'Unknown';
const senderPhone = String(msg.sender_pn || msg.sender?.id || msg.author || msg.from || '').replace(/@.*/, '');
const rawText = msg.text || msg.body || msg.message?.conversation || msg.conversation || msg.caption || '';
const fromMe = !!msg.fromMe;
const isGroup = chatId.endsWith('@g.us');

if (fromMe) {
  return [{ json: { skip: true, reason: 'fromMe' } }];
}

// Media detection — UAZAPI fields
const mediaTypeRaw = String(msg.mediaType || msg.type || msg.messageType || '').toLowerCase();
const isMedia = ['document','image','audio','video','sticker'].some(t => mediaTypeRaw.includes(t));
const mediaInfo = isMedia ? {
  type: mediaTypeRaw,
  fileName: msg.fileName || msg.filename || msg.documentName || msg.title || '',
  caption: msg.caption || msg.text || '',
  mimeType: msg.mimetype || msg.mimeType || '',
  url: msg.url || msg.fileUrl || msg.mediaUrl || ''
} : null;

const GROUPS = {
  '120363426390515923@g.us': { context: 'angelfly', label: 'Angel Fly Marketing Geral' },
  '120363420996892188@g.us': { context: 'garlic',   label: 'Garlic N Lemon | Branding' },
  '120363422948599063@g.us': { context: 'ernesto',  label: 'Ernesto | Site & Identidade Visual' }
};
const group = GROUPS[chatId] || { context: 'unknown', label: 'Unknown' };

const lower = String(rawText).toLowerCase();
const mentioned = /@\s*jarvis\b/.test(lower)
  || /\bjarvis\b/.test(lower)
  || (msg.mentioned_jid || []).some(j => String(j).includes('59739253801103'));

if (!mentioned && !isMedia) {
  return [{ json: { skip: true, reason: 'not_mentioned', chatId, messageId } }];
}

// If only media without mention, also skip (avoid responding to every photo in group)
if (!mentioned) {
  return [{ json: { skip: true, reason: 'media_without_mention', chatId, messageId } }];
}

const cleanText = String(rawText).replace(/@\s*jarvis\b/gi, '').replace(/\s+/g, ' ').trim();

// Allow empty cleanText if media (the file is the message)
if (!cleanText && !isMedia) {
  return [{ json: { skip: true, reason: 'empty_after_clean', chatId, messageId } }];
}

return [{
  json: {
    skip: false,
    chatId, messageId, senderName, senderPhone,
    rawText, cleanText: cleanText || '(sem texto, só anexo)',
    isGroup,
    groupContext: group.context,
    groupLabel: group.label,
    hasMedia: isMedia,
    mediaInfo,
    receivedAt: new Date().toISOString()
  }
}];

// ─────────────────────────────────────────────
// Resolve OpenAI thread_id (existing or null = create)
// ─────────────────────────────────────────────
const parsed = $('Parse & Filter Mention').item.json;
const convResp = $input.item.json;
const rows = Array.isArray(convResp) ? convResp : (convResp?.data || []);
const existing = rows.find(r => r && r.wa_chat_id === parsed.chatId);

return [{
  json: {
    ...parsed,
    threadId: existing?.openai_thread_id || null,
    convId: existing?.id || null,
    humorLevel: existing?.humor_level || 50,
    needsThread: !existing?.openai_thread_id
  }
}];

// Merge new threadId back into the data
const meta = $('Resolve Thread').item.json;
const threadResp = $input.item.json;
const threadId = threadResp.id || meta.threadId;
return [{ json: { ...meta, threadId, justCreatedThread: true } }];

// ─────────────────────────────────────────────
// Tool Dispatcher v2.2 — fail-loud on unresolved project/user
//  - If project_name given but not in DB -> error with available list
//  - If assigned_to_name given but not in DB -> error with team list
//  - get_today_briefing returns expanded scope (today + overdue + recent)
// ─────────────────────────────────────────────
const run = $input.item.json;
const toolCalls = run.required_action?.submit_tool_outputs?.tool_calls || [];
const COCKPIT = 'https://cockpit.angelfly.io/api';
const TOKEN = '5415d97c31b4ab3198a637234c4a76af86bd3d28ee9ebe9fe9c348f2f2c54c16';
const headers = { 'Authorization': 'Bearer ' + TOKEN, 'Content-Type': 'application/json' };

async function cockpitGet(path) {
  return await this.helpers.httpRequest({ method: 'GET', url: COCKPIT + path, headers, json: true, returnFullResponse: false });
}
async function cockpitPost(path, body) {
  return await this.helpers.httpRequest({ method: 'POST', url: COCKPIT + path, headers, body, json: true, returnFullResponse: false });
}

function norm(v) { return String(v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim(); }

async function fetchProjects() {
  const list = await cockpitGet.call(this, '/projects');
  return Array.isArray(list) ? list : (list?.data || []);
}
async function fetchUsers() {
  const list = await cockpitGet.call(this, '/users');
  return Array.isArray(list) ? list : (list?.data || []);
}

function resolveProject(name, projects) {
  if (!name) return { id: null, found: true, project: null };
  const t = norm(name);
  const match = projects.find(p => norm(p.name) === t)
    || projects.find(p => norm(p.name).includes(t))
    || projects.find(p => t.includes(norm(p.name)));
  if (match) return { id: match.id, found: true, project: match };
  return { id: null, found: false, available: projects.map(p => p.name) };
}
function resolveUser(name, users) {
  if (!name) return { id: null, found: true, user: null };
  const t = norm(name);
  const userName = (u) => u.name || u.full_name || u.username || '';
  const match = users.find(u => norm(userName(u)) === t)
    || users.find(u => norm(userName(u)).includes(t))
    || users.find(u => t.includes(norm(userName(u))));
  if (match) return { id: match.id, found: true, user: match };
  return { id: null, found: false, available: users.map(u => userName(u)) };
}

function filterByGroup(items, ctx) {
  if (!ctx || ctx === 'all') return items;
  return items.filter(it => {
    const blob = norm(it.project_name||'') + ' ' + norm(it.client_name||'');
    if (ctx === 'garlic')   return /garlic|gnl|lemons/.test(blob);
    if (ctx === 'ernesto')  return /ernesto|northend|north end|somerville|fax bridge|faxbridge/.test(blob);
    if (ctx === 'angelfly') return /angel\s*fly|angelfly|cockpit|jarvis/.test(blob);
    return true;
  });
}

const today = new Date(Date.now() - 3*3600000).toISOString().slice(0,10);
const isOpen = (s) => !['done','closed','cancelled','resolved','completed'].includes(norm(s));
const daysOverdue = (deadline) => {
  if (!deadline) return 0;
  const d = new Date(deadline.slice(0,10) + 'T12:00:00Z');
  const t = new Date(today + 'T12:00:00Z');
  return Math.max(0, Math.round((t - d) / 86400000));
};

function summarize(t) {
  return {
    id: t.id, title: t.title || t.subject,
    status: t.status || 'unknown',
    project_name: t.project_name || null,
    client_name: t.client_name || null,
    assigned_to_name: t.assigned_to_name || null,
    priority: t.priority || 'medium',
    deadline: t.deadline || null,
    days_overdue: t.deadline && t.deadline < today ? daysOverdue(t.deadline) : 0
  };
}

async function handleTool(call) {
  const name = call.function.name;
  let args = {};
  try { args = JSON.parse(call.function.arguments || '{}'); } catch (e) {}
  try {
    let output;
    switch (name) {
      case 'create_task':
      case 'create_ticket': {
        const projects = await fetchProjects.call(this);
        const users    = name === 'create_task' ? await fetchUsers.call(this) : [];

        const projRes = resolveProject(args.project_name, projects);
        if (args.project_name && !projRes.found) {
          output = {
            success: false,
            error: 'project_not_found',
            message: `Projeto '${args.project_name}' nao existe no Cockpit. Pergunte ao usuario qual eh o correto.`,
            available_projects: projRes.available
          };
          break;
        }
        const userRes = name === 'create_task' ? resolveUser(args.assigned_to_name, users) : { id: null, found: true };
        if (name === 'create_task' && args.assigned_to_name && !userRes.found) {
          output = {
            success: false,
            error: 'user_not_found',
            message: `Usuario '${args.assigned_to_name}' nao existe no Cockpit. Pergunte ao usuario quem deve receber a task.`,
            available_users: userRes.available
          };
          break;
        }

        const body = name === 'create_task' ? {
          title: args.title,
          description: args.description || '',
          project_id: projRes.id,
          project_name: projRes.project?.name || args.project_name || null,
          priority: args.priority || 'medium',
          status: 'backlog',
          deadline: args.deadline || null,
          assigned_to: userRes.id,
          assigned_to_name: userRes.user ? (userRes.user.name || userRes.user.full_name || userRes.user.username) : null
        } : {
          subject: args.subject,
          description: args.description || '',
          category: args.category || 'bug',
          priority: args.priority || 'medium',
          status: 'open',
          client_name: args.client_name || projRes.project?.client_name || null,
          project_id: projRes.id,
          project_name: projRes.project?.name || args.project_name || null
        };
        const created = await cockpitPost.call(this, name === 'create_task' ? '/tasks' : '/tickets', body);
        const newId = created.id || created.data?.id;
        if (!newId) {
          output = { success: false, error: 'create_failed', message: 'POST retornou sem id. Backend pode ter rejeitado.', raw: created };
        } else {
          output = { success: true, id: newId, ...body };
        }
        break;
      }
      case 'create_project': {
        const body = {
          name: args.name, client_name: args.client_name,
          scope_description: args.scope_description || '',
          status: 'active',
          payment_type: args.payment_type || 'one-time',
          total_budget: args.total_budget || 0
        };
        const created = await cockpitPost.call(this, '/projects', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_payment_incoming': {
        const body = {
          description: args.description || '', amount: args.amount,
          client_name: args.client_name, status: args.status || 'pending'
        };
        const created = await cockpitPost.call(this, '/payments_incoming', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_payment_outgoing': {
        const body = {
          description: args.description || '', amount: args.amount,
          recipient_name: args.recipient_name
        };
        const created = await cockpitPost.call(this, '/payments_outgoing', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_quote': {
        const body = {
          title: args.title, description: args.description || '',
          client_name: args.client_name, amount: args.amount,
          valid_until: args.valid_until || null, status: 'draft'
        };
        const created = await cockpitPost.call(this, '/quotes', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'list_projects': {
        const projects = await fetchProjects.call(this);
        output = projects.map(p => ({ id: p.id, name: p.name, client_name: p.client_name, status: p.status }));
        break;
      }
      case 'list_users': {
        const users = await fetchUsers.call(this);
        output = users.map(u => ({ id: u.id, name: u.name || u.full_name || u.username, role: u.role }));
        break;
      }
      case 'get_overdue_tasks': {
        const list = await cockpitGet.call(this, '/tasks?limit=300');
        const arr = Array.isArray(list) ? list : (list?.data || []);
        let overdue = arr.filter(t => isOpen(t.status) && t.deadline && t.deadline.slice(0,10) < today);
        if (args.group_context && args.group_context !== 'all') overdue = filterByGroup(overdue, args.group_context);
        overdue.sort((a,b) => daysOverdue(b.deadline) - daysOverdue(a.deadline));
        output = overdue.map(summarize);
        break;
      }
      case 'get_today_briefing': {
        const [tasksR, ticketsR] = await Promise.all([
          cockpitGet.call(this, '/tasks?limit=300'),
          cockpitGet.call(this, '/tickets?limit=300')
        ]);
        const allTasks   = filterByGroup(Array.isArray(tasksR)   ? tasksR   : (tasksR?.data || []),   args.group_context);
        const allTickets = filterByGroup(Array.isArray(ticketsR) ? ticketsR : (ticketsR?.data || []), args.group_context);
        const openTasks   = allTasks.filter(t => isOpen(t.status));
        const openTickets = allTickets.filter(t => isOpen(t.status));
        output = {
          group: args.group_context,
          today_tasks:    openTasks.filter(t => (t.deadline||'').slice(0,10) === today).map(summarize),
          overdue_tasks:  openTasks.filter(t => t.deadline && t.deadline.slice(0,10) < today).map(summarize),
          in_progress:    openTasks.filter(t => norm(t.status) === 'in_progress' || norm(t.status) === 'assigned').map(summarize),
          backlog:        openTasks.filter(t => norm(t.status) === 'backlog').slice(0, 10).map(summarize),
          review:         openTasks.filter(t => norm(t.status) === 'review' || norm(t.status) === 'client_approval').map(summarize),
          recent_tickets: openTickets.slice(0, 10).map(summarize),
          totals: { open_tasks: openTasks.length, open_tickets: openTickets.length }
        };
        break;
      }
      default:
        output = { error: 'unknown_tool: ' + name };
    }
    return { tool_call_id: call.id, output: JSON.stringify(output) };
  } catch (err) {
    return { tool_call_id: call.id, output: JSON.stringify({ success: false, error: 'exception', message: err.message }) };
  }
}

const results = [];
for (const c of toolCalls) {
  const r = await handleTool.call(this, c);
  results.push(r);
}

return [{ json: { tool_outputs: results, runId: run.id, threadId: run.thread_id } }];

// Extract assistant text from response
const data = $input.item.json;
const messages = data.data || [];
const assistantMsg = messages.find(m => m.role === 'assistant');
let text = '';
if (assistantMsg) {
  const blocks = assistantMsg.content || [];
  text = blocks.filter(b => b.type === 'text').map(b => b.text?.value || '').join('\n').trim();
}
if (!text) text = '🤖 (sem resposta)';

const meta = $('Resolve Thread').item.json;
return [{ json: { ...meta, replyText: text, threadId: $('Merge New Thread').item.json?.threadId || meta.threadId } }];

// Build error reply
const run = $input.item.json;
const meta = $('Parse & Filter Mention').item.json;
let text = '⚠️ Jarvis: deu ruim aqui. ';
if (run.last_error?.message) text += '(' + run.last_error.message + ') ';
text += 'Tenta de novo em 30s.';
return [{ json: { ...meta, replyText: text } }];

// Build user message with live context (projects + team + media + OpenAI file upload)
const meta = $('Merge New Thread').first()?.json || $('Resolve Thread').first().json;
const projResp = $('Fetch Projects (context)').item.json;
const userResp = $('Fetch Users (context)').item.json;

const UAZAPI_TOKEN = 'a232b655-1733-46c1-b872-1f82782b9cbe';
const OPENAI_KEY = '__JARVIS_OPENAI_KEY__';

const projects = Array.isArray(projResp) ? projResp : (projResp?.data || []);
const users    = Array.isArray(userResp) ? userResp : (userResp?.data || []);

const activeProjects = projects.filter(p => (p.status || 'active') !== 'inactive')
  .map(p => `- ${p.name}${p.client_name ? ' (cliente: ' + p.client_name + ')' : ''} [id=${p.id}]`)
  .join('\n');
const teamList = users.filter(u => u.status !== 'inactive')
  .map(u => `- ${u.name || u.full_name || u.username} [id=${u.id}, role=${u.role || 'unknown'}]`)
  .join('\n');

// ── Phase 2: download from UAZAPI + upload to OpenAI Files ──
let openai_file_id = null;
let mediaBlock = '';
let mediaError = null;

if (meta.hasMedia && meta.messageId) {
  const m = meta.mediaInfo || {};
  try {
    // 1. Get download URL from UAZAPI
    const dl = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://angelfly.uazapi.com/message/download',
      headers: { 'token': UAZAPI_TOKEN, 'Content-Type': 'application/json' },
      body: { id: meta.messageId, return_link: true, transcribe: false },
      json: true,
      returnFullResponse: false
    });
    const fileURL = dl?.fileURL || dl?.url || dl?.link || dl?.fileUrl || dl?.data?.fileURL;

    if (!fileURL) {
      mediaError = 'no_url_returned';
    } else {
      // 2. Download binary
      const binary = await this.helpers.httpRequest({
        method: 'GET',
        url: fileURL,
        encoding: 'arraybuffer',
        returnFullResponse: false
      });

      // 3. Upload to OpenAI Files (multipart)
      const buf = Buffer.from(binary);
      const filename = m.fileName || ('attachment_' + Date.now() + (m.mimeType?.includes('pdf') ? '.pdf' : ''));
      const upload = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.openai.com/v1/files',
        headers: { 'Authorization': 'Bearer ' + OPENAI_KEY },
        formData: {
          file: { value: buf, options: { filename, contentType: m.mimeType || 'application/octet-stream' } },
          purpose: 'assistants'
        },
        json: true,
        returnFullResponse: false
      });
      openai_file_id = upload?.id || upload?.data?.id;

      if (!openai_file_id) mediaError = 'no_file_id_from_openai';
    }
  } catch (err) {
    mediaError = 'exception: ' + (err.message || err);
  }

  if (openai_file_id) {
    mediaBlock = `\n\n[ARQUIVO ANEXO: tipo=${m.type || '?'}${m.fileName ? ', nome="' + m.fileName + '"' : ''}${m.caption ? ', legenda="' + m.caption + '"' : ''}]\n[FILE_ID OPENAI: ${openai_file_id} — voce TEM acesso ao conteudo via file_search]`;
  } else {
    mediaBlock = `\n\n[ARQUIVO ANEXO: tipo=${m.type || '?'}${m.fileName ? ', nome="' + m.fileName + '"' : ''}${m.caption ? ', legenda="' + m.caption + '"' : ''}]\n[Erro ao processar arquivo: ${mediaError || 'desconhecido'} — peca pro usuario descrever em texto]`;
  }
}

const content = `[Grupo: ${meta.groupLabel} | Contexto: ${meta.groupContext} | De: ${meta.senderName}]

CONTEXTO ATUAL DO COCKPIT (use estes nomes EXATOS ao chamar tools):

PROJETOS ATIVOS:
${activeProjects || '(nenhum)'}

EQUIPE:
${teamList || '(nenhum)'}

MENSAGEM DO USUARIO:
${meta.cleanText}${mediaBlock}`;

// Build the full OpenAI message body (with attachments if file uploaded)
const messageBody = { role: 'user', content };
if (openai_file_id) {
  messageBody.attachments = [{ file_id: openai_file_id, tools: [{ type: 'file_search' }] }];
}

return [{ json: { ...meta, content, messageBody, openai_file_id, mediaError, threadId: meta.threadId } }];
